#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
long long a[5050],b[5050];
long long fastpow(long long x,long long y)
{
	long long ans=1;
	while(y)
	{
		if(y&1)
		{
			ans=ans*x%mod;
		}
		x=x*x%mod;
		y>>=1;
	}
	return ans;
}
int main()
{
	long long n;
	scanf("%lld",&n);
	for(long long i=0;i<n;i++)
	{
		scanf("%lld",&a[i]);
	}
	for(long long i=0;i<=n;i++)
	{
		scanf("%lld",&b[i]);
	}
	long long ans=0,sum=0,sum1=0;
	for(long long i=n;i>=0;i--)
	{
		sum1=(sum1+b[i])%mod;
		ans=(ans+sum*b[i]%mod)%mod;
		sum=(sum+a[n-i])%mod;
	}
	printf("%lld",ans*fastpow(sum1,mod-2)%mod);
	return 0;
}
